class Solution(object):
    def canPartitionGrid(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: bool
        """
        m = len(grid)
        n = len(grid[0])
        total = sum(sum(row) for row in grid)

        if total % 2 != 0:
            return False

        target = total // 2

        # Try horizontal cuts
        for i in range(1, m):
            top_sum = sum(sum(grid[r]) for r in range(i))
            bottom_sum = total - top_sum

            if top_sum == bottom_sum:
                return True
            if top_sum == bottom_sum - grid[i][0]:
                return True
            if top_sum - grid[i-1][0] == bottom_sum:
                return True

        # Try vertical cuts
        for j in range(1, n):
            left_sum = sum(grid[r][c] for r in range(m) for c in range(j))
            right_sum = total - left_sum

            if left_sum == right_sum:
                return True
            if left_sum == right_sum - grid[0][j]:
                return True
            if left_sum - grid[0][j-1] == right_sum:
                return True

        return False
